export interface SubmitJobPayload {
    repository: string;
    branch: string;
    commitSha: string;
    buildCommand: string;
    dockerImage: string;
    timeoutMinutes: number;
    artifactPaths: string[];
    environmentVariables: Record<string, string>;
    tags: string[];
    workingDirectory: string;
    /**
     * GitHub token forwarded to the agent so it can clone private repositories.
     * This is a short-lived installation token generated by GitHub for the
     * current workflow run and is scoped to the repository contents.
     */
    githubToken?: string;
    metadata: {
        githubRunId: string;
        githubRunNumber: string;
        githubActor: string;
        githubEventName: string;
        githubWorkflow: string;
    };
}
export interface SubmitJobResult {
    success: boolean;
    jobId?: string;
    queuePosition?: number;
    error?: string;
}
/**
 * Submit a job to the BuildHive server
 */
export declare function submitJob(serverUrl: string, apiKey: string, payload: SubmitJobPayload): Promise<SubmitJobResult>;
